azure:analysisservices/server:Server.description:
Manages an Analysis Services Server.

{{% examples %}}
## Example Usage
{{% example %}}

```typescript
import * as codeinfra from "@codeinfra/codeinfra";
import * as azure from "@codeinfra/azure";

const rg = new azure.core.ResourceGroup("rg", {location: "West Europe"});
const server = new azure.analysisservices.Server("server", {
    location: "northeurope",
    resourceGroupName: rg.name,
    sku: "S0",
    adminUsers: ["myuser@domain.tld"],
    enablePowerBiService: true,
    ipv4FirewallRules: [{
        name: "myRule1",
        rangeStart: "210.117.252.0",
        rangeEnd: "210.117.252.255",
    }],
    tags: {
        abc: 123,
    },
});
```
```python
import codeinfra
import codeinfra_azure as azure

rg = azure.core.ResourceGroup("rg", location="West Europe")
server = azure.analysisservices.Server("server",
    location="northeurope",
    resource_group_name=rg.name,
    sku="S0",
    admin_users=["myuser@domain.tld"],
    enable_power_bi_service=True,
    ipv4_firewall_rules=[azure.analysisservices.ServerIpv4FirewallRuleArgs(
        name="myRule1",
        range_start="210.117.252.0",
        range_end="210.117.252.255",
    )],
    tags={
        "abc": "123",
    })
```
```csharp
using Codeinfra;
using Azure = Codeinfra.Azure;

class MyStack : Stack
{
    public MyStack()
    {
        var rg = new Azure.Core.ResourceGroup("rg", new Azure.Core.ResourceGroupArgs
        {
            Location = "West Europe",
        });
        var server = new Azure.AnalysisServices.Server("server", new Azure.AnalysisServices.ServerArgs
        {
            Location = "northeurope",
            ResourceGroupName = rg.Name,
            Sku = "S0",
            AdminUsers = 
            {
                "myuser@domain.tld",
            },
            EnablePowerBiService = true,
            Ipv4FirewallRules = 
            {
                new Azure.AnalysisServices.Inputs.ServerIpv4FirewallRuleArgs
                {
                    Name = "myRule1",
                    RangeStart = "210.117.252.0",
                    RangeEnd = "210.117.252.255",
                },
            },
            Tags = 
            {
                { "abc", "123" },
            },
        });
    }

}
```
```go
package main

import (
	"github.com/khulnasoft/codeinfra-azure/sdk/v4/go/azure/analysisservices"
	"github.com/khulnasoft/codeinfra-azure/sdk/v4/go/azure/core"
	"github.com/khulnasoft/codeinfra/sdk/v3/go/codeinfra"
)

func main() {
	codeinfra.Run(func(ctx *codeinfra.Context) error {
		rg, err := core.NewResourceGroup(ctx, "rg", &core.ResourceGroupArgs{
			Location: codeinfra.String("West Europe"),
		})
		if err != nil {
			return err
		}
		_, err = analysisservices.NewServer(ctx, "server", &analysisservices.ServerArgs{
			Location:          codeinfra.String("northeurope"),
			ResourceGroupName: rg.Name,
			Sku:               codeinfra.String("S0"),
			AdminUsers: codeinfra.StringArray{
				codeinfra.String("myuser@domain.tld"),
			},
			EnablePowerBiService: codeinfra.Bool(true),
			Ipv4FirewallRules: analysisservices.ServerIpv4FirewallRuleArray{
				&analysisservices.ServerIpv4FirewallRuleArgs{
					Name:       codeinfra.String("myRule1"),
					RangeStart: codeinfra.String("210.117.252.0"),
					RangeEnd:   codeinfra.String("210.117.252.255"),
				},
			},
			Tags: codeinfra.StringMap{
				"abc": codeinfra.String("123"),
			},
		})
		if err != nil {
			return err
		}
		return nil
	})
}
```

> **NOTE:** The server resource will automatically be started and stopped during an update if it is in `paused` state.
{{% /example %}}
{{% /examples %}}

## Import

Analysis Services Server can be imported using the `resource id`, e.g.

```sh
 $ codeinfra import azure:analysisservices/server:Server server /subscriptions/00000000-0000-0000-0000-000000000000/resourceGroups/resourcegroup1/providers/Microsoft.AnalysisServices/servers/server1
```

azure:apimanagement/api:Api.description:
Manages an API within an API Management Service.

{{% examples %}}
## Example Usage
{{% example %}}

```typescript
import * as codeinfra from "@codeinfra/codeinfra";
import * as azure from "@codeinfra/azure";

const exampleResourceGroup = new azure.core.ResourceGroup("exampleResourceGroup", {location: "West Europe"});
const exampleService = new azure.apimanagement.Service("exampleService", {
    location: exampleResourceGroup.location,
    resourceGroupName: exampleResourceGroup.name,
    publisherName: "My Company",
    publisherEmail: "company@exmaple.com",
    skuName: "Developer_1",
});
const exampleApi = new azure.apimanagement.Api("exampleApi", {
    resourceGroupName: exampleResourceGroup.name,
    apiManagementName: exampleService.name,
    revision: "1",
    displayName: "Example API",
    path: "example",
    protocols: ["https"],
    "import": {
        contentFormat: "swagger-link-json",
        contentValue: "http://conferenceapi.azurewebsites.net/?format=json",
    },
});
```
