	"github.com/khulnasoft/codeinfra-azure/sdk/v4/go/azure/apimanagement"
	"github.com/khulnasoft/codeinfra-azure/sdk/v4/go/azure/core"
	"github.com/khulnasoft/codeinfra/sdk/v3/go/codeinfra"
)

func main() {
	codeinfra.Run(func(ctx *codeinfra.Context) error {
		exampleResourceGroup, err := core.NewResourceGroup(ctx, "exampleResourceGroup", &core.ResourceGroupArgs{
			Location: codeinfra.String("West Europe"),
		})
		if err != nil {
			return err
		}
		exampleService, err := apimanagement.NewService(ctx, "exampleService", &apimanagement.ServiceArgs{
			Location:          exampleResourceGroup.Location,
			ResourceGroupName: exampleResourceGroup.Name,
			PublisherName:     codeinfra.String("pub1"),
			PublisherEmail:    codeinfra.String("pub1@email.com"),
			SkuName:           codeinfra.String("Developer_1"),
		})
		if err != nil {
			return err
		}
		_, err = apimanagement.NewApiVersionSet(ctx, "exampleApiVersionSet", &apimanagement.ApiVersionSetArgs{
			ResourceGroupName: exampleResourceGroup.Name,
			ApiManagementName: exampleService.Name,
			DisplayName:       codeinfra.String("ExampleAPIVersionSet"),
			VersioningScheme:  codeinfra.String("Segment"),
		})
		if err != nil {
			return err
		}
		return nil
	})
}
```
