```typescript
import * as codeinfra from "@codeinfra/codeinfra";
import * as azure from "@codeinfra/azure";
import * as azuread from "@codeinfra/azuread";

const exampleResourceGroup = new azure.core.ResourceGroup("exampleResourceGroup", {location: "West Europe"});
const current = azure.core.getClientConfig({});
const exampleServicePrincipal = azuread.getServicePrincipal({
    displayName: "Azure Spring Cloud Domain-Management",
});
const exampleKeyVault = new azure.keyvault.KeyVault("exampleKeyVault", {
    location: exampleResourceGroup.location,
    resourceGroupName: exampleResourceGroup.name,
    tenantId: current.then(current => current.tenantId),
    skuName: "standard",
    accessPolicies: [
        {
            tenantId: current.then(current => current.tenantId),
            objectId: current.then(current => current.objectId),
            secretPermissions: ["set"],
            certificatePermissions: [
                "create",
                "delete",
                "get",
                "update",
            ],
        },
        {
            tenantId: current.then(current => current.tenantId),
            objectId: exampleServicePrincipal.then(exampleServicePrincipal => exampleServicePrincipal.objectId),
            secretPermissions: [
                "get",
                "list",
            ],
            certificatePermissions: [
                "get",
                "list",
            ],
        },
    ],
});
const exampleCertificate = new azure.keyvault.Certificate("exampleCertificate", {
    keyVaultId: exampleKeyVault.id,
    certificatePolicy: {
        issuerParameters: {
            name: "Self",
        },
        keyProperties: {
            exportable: true,
            keySize: 2048,
            keyType: "RSA",
            reuseKey: true,
        },
        lifetimeActions: [{
            action: {
                actionType: "AutoRenew",
            },
            trigger: {
                daysBeforeExpiry: 30,
            },
        }],
        secretProperties: {
            contentType: "application/x-pkcs12",
        },
        x509CertificateProperties: {
            keyUsages: [
                "cRLSign",
                "dataEncipherment",
                "digitalSignature",
                "keyAgreement",
                "keyCertSign",
                "keyEncipherment",
            ],
            subject: "CN=contoso.com",
            validityInMonths: 12,
        },
    },
});
const exampleSpringCloudService = new azure.appplatform.SpringCloudService("exampleSpringCloudService", {
    resourceGroupName: exampleResourceGroup.name,
    location: exampleResourceGroup.location,
});
const exampleSpringCloudCertificate = new azure.appplatform.SpringCloudCertificate("exampleSpringCloudCertificate", {
    resourceGroupName: exampleSpringCloudService.resourceGroupName,
    serviceName: exampleSpringCloudService.name,
    keyVaultCertificateId: exampleCertificate.id,
});
```
