```go
package main

import (
	"fmt"

	"github.com/khulnasoft/codeinfra-azure/sdk/v4/go/azure/compute"
	"github.com/khulnasoft/codeinfra-azure/sdk/v4/go/azure/core"
	"github.com/khulnasoft/codeinfra-azure/sdk/v4/go/azure/network"
	"github.com/khulnasoft/codeinfra-azure/sdk/v4/go/azure/storage"
	"github.com/khulnasoft/codeinfra/sdk/v3/go/codeinfra"
)

func main() {
	codeinfra.Run(func(ctx *codeinfra.Context) error {
		exampleResourceGroup, err := core.NewResourceGroup(ctx, "exampleResourceGroup", &core.ResourceGroupArgs{
			Location: codeinfra.String("West Europe"),
		})
		if err != nil {
			return err
		}
		exampleVirtualNetwork, err := network.NewVirtualNetwork(ctx, "exampleVirtualNetwork", &network.VirtualNetworkArgs{
			AddressSpaces: codeinfra.StringArray{
				codeinfra.String("10.0.0.0/16"),
			},
			Location:          exampleResourceGroup.Location,
			ResourceGroupName: exampleResourceGroup.Name,
		})
		if err != nil {
			return err
		}
		exampleSubnet, err := network.NewSubnet(ctx, "exampleSubnet", &network.SubnetArgs{
			ResourceGroupName:  exampleResourceGroup.Name,
			VirtualNetworkName: exampleVirtualNetwork.Name,
			AddressPrefixes: codeinfra.StringArray{
				codeinfra.String("10.0.2.0/24"),
			},
		})
		if err != nil {
			return err
		}
		exampleNetworkInterface, err := network.NewNetworkInterface(ctx, "exampleNetworkInterface", &network.NetworkInterfaceArgs{
			Location:          exampleResourceGroup.Location,
			ResourceGroupName: exampleResourceGroup.Name,
			IpConfigurations: network.NetworkInterfaceIpConfigurationArray{
				&network.NetworkInterfaceIpConfigurationArgs{
					Name:                       codeinfra.String("testconfiguration1"),
					SubnetId:                   exampleSubnet.ID(),
					PrivateIpAddressAllocation: codeinfra.String("Dynamic"),
				},
			},
		})
		if err != nil {
			return err
		}
		exampleAccount, err := storage.NewAccount(ctx, "exampleAccount", &storage.AccountArgs{
			ResourceGroupName:      exampleResourceGroup.Name,
			Location:               exampleResourceGroup.Location,
			AccountTier:            codeinfra.String("Standard"),
			AccountReplicationType: codeinfra.String("LRS"),
			Tags: codeinfra.StringMap{
				"environment": codeinfra.String("staging"),
			},
		})
		if err != nil {
			return err
		}
		exampleContainer, err := storage.NewContainer(ctx, "exampleContainer", &storage.ContainerArgs{
			StorageAccountName:  exampleAccount.Name,
			ContainerAccessType: codeinfra.String("private"),
		})
		if err != nil {
			return err
		}
		exampleVirtualMachine, err := compute.NewVirtualMachine(ctx, "exampleVirtualMachine", &compute.VirtualMachineArgs{
			Location:          exampleResourceGroup.Location,
			ResourceGroupName: exampleResourceGroup.Name,
			NetworkInterfaceIds: codeinfra.StringArray{
				exampleNetworkInterface.ID(),
			},
			VmSize: codeinfra.String("Standard_F2"),
			StorageImageReference: &compute.VirtualMachineStorageImageReferenceArgs{
				Publisher: codeinfra.String("Canonical"),
				Offer:     codeinfra.String("UbuntuServer"),
				Sku:       codeinfra.String("16.04-LTS"),
				Version:   codeinfra.String("latest"),
			},
			StorageOsDisk: &compute.VirtualMachineStorageOsDiskArgs{
				Name: codeinfra.String("myosdisk1"),
				VhdUri: codeinfra.All(exampleAccount.PrimaryBlobEndpoint, exampleContainer.Name).ApplyT(func(_args []interface{}) (string, error) {
					primaryBlobEndpoint := _args[0].(string)
					name := _args[1].(string)
					return fmt.Sprintf("%v%v%v", primaryBlobEndpoint, name, "/myosdisk1.vhd"), nil
				}).(codeinfra.StringOutput),
				Caching:      codeinfra.String("ReadWrite"),
				CreateOption: codeinfra.String("FromImage"),
			},
			OsProfile: &compute.VirtualMachineOsProfileArgs{
				ComputerName:  codeinfra.String("hostname"),
				AdminUsername: codeinfra.String("testadmin"),
				AdminPassword: codeinfra.String("Password1234!"),
			},
			OsProfileLinuxConfig: &compute.VirtualMachineOsProfileLinuxConfigArgs{
				DisablePasswordAuthentication: codeinfra.Bool(false),
			},
			Tags: codeinfra.StringMap{
				"environment": codeinfra.String("staging"),
			},
		})
		if err != nil {
			return err
		}
		_, err = compute.NewExtension(ctx, "exampleExtension", &compute.ExtensionArgs{
			VirtualMachineId:   exampleVirtualMachine.ID(),
			Publisher:          codeinfra.String("Microsoft.Azure.Extensions"),
			Type:               codeinfra.String("CustomScript"),
			TypeHandlerVersion: codeinfra.String("2.0"),
			Settings: codeinfra.String(fmt.Sprintf("%v%v%v", "	{\n", "		\"commandToExecute\": \"hostname && uptime\"\n", "	}\n")),
			Tags: codeinfra.StringMap{
				"environment": codeinfra.String("Production"),
			},
		})
		if err != nil {
			return err
		}
		return nil
	})
}
